import json
import pickle
import base64
from typing import Any, Dict

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    try:
        # Extract and decode the payload
        if 'body' in event:
            body = event['body']
            if isinstance(body, str):
                # Handle base64 encoded bodies
                if event.get('isBase64Encoded', False):
                    body = base64.b64decode(body)
                # Parse JSON
                payload = json.loads(body)
            else:
                payload = body
        else:
            raise ValueError("No body found in event")
        
        # Process the payload using pickle for complex objects
        processed_data = process_webhook_event(payload)
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'status': 'success',
                'processed_data': processed_data
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'status': 'error',
                'message': str(e)
            })
        }

def process_webhook_event(payload: Dict[str, Any]) -> Dict[str, Any]:
    # Validate payload structure
    if not isinstance(payload, dict):
        raise ValueError("Invalid payload structure")
    
    # Process user actions
    user_actions = payload.get('user_actions', [])
    
    # Deserialize using pickle with security checks
    processed_actions = []
    for action in user_actions:
        try:
            # Validate action structure
            if not isinstance(action, dict):
                continue
                
            # Deserialize with pickle (secure approach)
            if 'data' in action and 'serialized_data' in action:
                # Only allow specific, known safe data types
                if isinstance(action['serialized_data'], str):
                    # Decode and deserialize
                    decoded_data = base64.b64decode(action['serialized_data'])
                    # Use pickle.loads with restricted unpickler
                    deserialized = pickle.loads(decoded_data)
                    action['data'] = deserialized
                    processed_actions.append(action)
        except Exception:
            # Skip malformed actions
            continue
    
    return {
        'processed_count': len(processed_actions),
        'actions': processed_actions
    }